251			return emptyColor
252		}
253	
254		if ansiColor.IsTransparent() {
255			return ansiColor
256		}
257	
258		if ansiColor == Accent {
259			if d.accent == nil {
260				return emptyColor
261			}
262	
263			if isBackground {
264				return d.accent.Background
265			}
266	
267			return d.accent.Foreground
268		}
269	
270		colorFromName, err := getAnsiColorFromName(ansiColor, isBackground)
271		if err == nil {
272			return colorFromName
273		}
274	
275		colorString := ansiColor.String()
276	
277		if !strings.HasPrefix(colorString, "#") {
278			val, err := strconv.ParseUint(colorString, 10, 64)
279			if err != nil || val > 255 {
280				return emptyColor
281			}
282	
283			c256 := color.C256(uint8(val), isBackground)
284			return Ansi(c256.String())
285		}
