288		if !style.IsEmpty() {
289			if TrueColor {
290				return Ansi(style.String())
291			}
292	
293			return Ansi(style.C256().String())
294		}
295	
296		if colorInt, err := strconv.ParseInt(colorString, 10, 8); err == nil {
297			c := color.C256(uint8(colorInt), isBackground)
