360		if c.colorCache == nil {
361			c.colorCache = make(map[cachedColorKey]Ansi)
362		}
363	
364		key := cachedColorKey{colorString, isBackground}
365		if ansiColor, hit := c.colorCache[key]; hit {
366			return ansiColor
367		}
368	
369		ansiColor := c.ansiColors.ToAnsi(colorString, isBackground)
370		c.colorCache[key] = ansiColor
371		return ansiColor
372	}
